+    for (const forbidden of [
+      "./index",
+      "./api",
+      "./runtime-api",
+      "./src/setup",
+      "./src/stream",
+      "./src/embedding-provider",
+      "./src/memory-embedding-adapter",
+      "./src/web-search-provider",
+      "openclaw/plugin-sdk/text-runtime",
+      "openclaw/plugin-sdk/plugin-entry",
+    ]) {
