+const PROVIDER_ID = "ollama";
+const DEFAULT_API_KEY = "ollama-local";
+const OLLAMA_CONTEXT_ENRICH_LIMIT = 200;
+
+type OllamaPluginConfig = {
+  discovery?: {
+    enabled?: boolean;
+  };
+};
